    (re.compile(r"客户.*(?:画像|分布|结构|分层)"), IntentType.customer_portrait),
    (re.compile(r"客群.*(?:画像|分布|结构)"), IntentType.customer_portrait),
    (re.compile(r"(?:客温|客价).*(?:分布|画像)"), IntentType.customer_portrait),
    (re.compile(r"(?:队伍|团队).*(?:画像|分布|结构|分层|人力)"), IntentType.team_portrait),
    (re.compile(r"人力.*(?:画像|分布|结构)"), IntentType.team_portrait),
]

def try_homepage_intent(user_message) -> Optional[IntentResult]:
    normalized = re.sub(r"\s+", "", user_message)
    for pattern, intent in _HOMEPAGE_RULES:
        if pattern.search(normalized):
            return IntentResult(intent=intent, confidence=1.0)

def try_rule_based_intent(user_message, contexts=None) -> Optional[IntentResult]:
    normalized = re.sub(r"\s+", "", user_message)
    has_planning_ctx = _has_completed_planning_context(contexts)

    # Tier 1: adjustment intents after planning context
    if has_planning_ctx and _is_target_adjustment_message(normalized):
        return IntentResult(intent=IntentType.target_value_adjustment, confidence=1.0,
                            target_value=_extract_target_value_from_contexts(contexts))
    adj_paths = extract_path_types_from_text(user_message) or _extract_path_types_by_keywords(normalized)
    if has_planning_ctx and adj_paths and _is_measurement_adjustment_message(normalized):
        return IntentResult(intent=IntentType.achievement_measurement_adjustment, confidence=1.0,
                            target_value=_extract_target_value_from_contexts(contexts), path_types=adj_paths)
    if has_planning_ctx and _is_planning_fallback_message(normalized):
        return IntentResult(intent=IntentType.nbev_planning_fallback, confidence=0.95,
                            target_value=_extract_target_value_from_contexts(contexts), path_types=adj_paths)

    # Tier 0: homepage
    if result := try_homepage_intent(user_message): return result

    # Tier 2: structured extraction
    tv = extract_target_value_from_text(user_message)
    pt = extract_path_types_from_text(user_message)
    if tv is not None or pt is not None:
        return IntentResult(intent=IntentType.nbev_planning, confidence=1.0, target_value=tv, path_types=pt)

    # Tier 3: keyword heuristic (NBEV + planning keyword)
    if "NBEV" in normalized.upper() and any(k in normalized for k in ("达成","规划","路径","测算","分析")):
        return IntentResult(intent=IntentType.nbev_planning, confidence=0.95)

# Context check markers: "NEXT_STEP_CARD", "TEAM_REACH_MEASUREMENT", "CUSTOMER_REACH_MEASUREMEN", "PRODUCT_REACH_MEASUREMENT", "达成路径", "达成测算", "路径规划"
def _has_completed_planning_context(contexts) -> bool: ...

# Target extraction patterns from context: "targetNbev":value, "target_nbev":value, "target_value":value, "目标值" digits万, "NBEV目标" digits万
def _extract_target_value_from_contexts(contexts) -> Optional[str]: ...

# Adjustment triggers: "调整目标","修改目标","重设目标","重新设置目标","换个目标"
# Measurement adjustment: "重新测算","重新规划","规划","测算" + path keywords ("队伍","团队","客户","产品")
# Planning fallback: "调整","修改","改","AI研判","研判","分析结果","达成路径","测算" + NBEV/target/path keywords

async def recognize_intent(user_message, contexts=None) -> IntentResult:
